const now = new Date().toISOString();

function rowsFrom(x) {
  if (Array.isArray(x)) return x;
  if (x && Array.isArray(x.data)) return x.data;
  if (x && x.data && Array.isArray(x.data.data)) return x.data.data;
  if (x && x.data && Array.isArray(x.data.list)) return x.data.list;
  if (x && Array.isArray(x.list)) return x.list;
  return [];
}

function toNum(v) {
  if (v === null || v === undefined || v === '') return null;
  const n = Number(String(v).replace(',', '.'));
  return Number.isFinite(n) ? n : null;
}

function pct(cur, prev) {
  if (cur === null || prev === null || prev === 0) return null;
  return Number((((cur - prev) / prev) * 100).toFixed(4));
}

const rawRows = rowsFrom($json);
const normalized = rawRows
  .map((r) => {
    const year = Number(r.year ?? r.Year ?? r.year_code ?? r['Year Code']);
    const monthCode = Number(r.months_code ?? r['Months Code'] ?? r.monthCode ?? 0);
    const month = String(r.months ?? r.Months ?? r.month ?? '').trim() || null;
    const elementCode = String(r.element_code ?? r['Element Code'] ?? r.elementCode ?? '');
    const element = String(r.element ?? r.Element ?? '');
    const value = toNum(r.value ?? r.Value);

    if (!Number.isInteger(year) || !monthCode) return null;
    return {
      year,
      month_code: monthCode,
      month,
      element_code: elementCode,
      element,
      value,
    };
  })
  .filter(Boolean)
  .sort((a, b) => (a.year - b.year) || (a.month_code - b.month_code) || a.element_code.localeCompare(b.element_code));

const byPeriod = new Map();
for (const row of normalized) {
  const key = `${row.year}-${row.month_code}`;
  const entry = byPeriod.get(key) || {
    year: row.year,
    month_code: row.month_code,
    month: row.month,
    producer_price_lcu_per_tonne: null,
    producer_price_index: null,
  };

  if (row.element_code === '5530') entry.producer_price_lcu_per_tonne = row.value;
  if (row.element_code === '5539') entry.producer_price_index = row.value;

  byPeriod.set(key, entry);
}

const series = Array.from(byPeriod.values()).sort((a, b) => (a.year - b.year) || (a.month_code - b.month_code));
const monthlySeries = series.filter((r) => r.month_code >= 7001 && r.month_code <= 7012);
const annualSeries = series.filter((r) => r.month_code === 7021);

const monthlyPriceSeries = monthlySeries.filter((r) => r.producer_price_lcu_per_tonne !== null);
const latestMonthly = monthlyPriceSeries.length
  ? monthlyPriceSeries[monthlyPriceSeries.length - 1]
  : (monthlySeries[monthlySeries.length - 1] || null);
const previousMonthly = monthlyPriceSeries.length > 1 ? monthlyPriceSeries[monthlyPriceSeries.length - 2] : null;

let sameMonthPreviousYear = null;
if (latestMonthly) {
  sameMonthPreviousYear = monthlyPriceSeries.find(
    (r) => r.year === latestMonthly.year - 1 && r.month_code === latestMonthly.month_code,
  ) || null;
}

const latestAnnual = annualSeries.length ? annualSeries[annualSeries.length - 1] : null;
const previousAnnual = annualSeries.length > 1 ? annualSeries[annualSeries.length - 2] : null;

const momPricePct = latestMonthly && previousMonthly
  ? pct(latestMonthly.producer_price_lcu_per_tonne, previousMonthly.producer_price_lcu_per_tonne)
  : null;
const yoyPricePct = latestMonthly && sameMonthPreviousYear
  ? pct(latestMonthly.producer_price_lcu_per_tonne, sameMonthPreviousYear.producer_price_lcu_per_tonne)
  : null;
const annualPriceYoyPct = latestAnnual && previousAnnual
  ? pct(latestAnnual.producer_price_lcu_per_tonne, previousAnnual.producer_price_lcu_per_tonne)
  : null;

let summary = 'FAOSTAT PP producer-price series is not available for the selected filter.';
if (latestMonthly) {
  const monthNum = Math.max(1, latestMonthly.month_code - 7000);
  summary = `FAOSTAT PP latest monthly producer price for Brazil coffee is ${latestMonthly.producer_price_lcu_per_tonne ?? 'n/a'} LCU/tonne in ${latestMonthly.year}-${String(monthNum).padStart(2, '0')}.`;
} else if (latestAnnual) {
  summary = `FAOSTAT PP latest annual producer price for Brazil coffee is ${latestAnnual.producer_price_lcu_per_tonne ?? 'n/a'} LCU/tonne in ${latestAnnual.year}.`;
}

return [{
  json: {
    source: 'FAOSTAT_PP',
    dataset_code: 'PP',
    country: 'BR',
    item_code: '656',
    item_name: 'Coffee, green',
    collected_at: now,
    pp_latest_monthly: latestMonthly,
    pp_previous_monthly: previousMonthly,
    pp_same_month_previous_year: sameMonthPreviousYear,
    pp_latest_annual: latestAnnual,
    pp_previous_annual: previousAnnual,
    pp_recent_monthly_series: monthlySeries.slice(-18),
    pp_recent_annual_series: annualSeries.slice(-8),
    pp_derived_metrics: {
      mom_price_pct: momPricePct,
      yoy_price_pct: yoyPricePct,
      annual_price_yoy_pct: annualPriceYoyPct,
    },
    pp_summary_en: summary,
  },
}];

function getCollectedPeriod(isoTs, cadenza) {
  const d = new Date(isoTs || new Date().toISOString());
  const pad = n => String(n).padStart(2, '0');
  const yyyy = d.getUTCFullYear();
  const mm = pad(d.getUTCMonth() + 1);
  const dd = pad(d.getUTCDate());
  const hh = pad(d.getUTCHours());
  const doy = Math.floor((d - new Date(Date.UTC(yyyy,0,1))) / 86400000);
  const week = pad(Math.ceil((doy + new Date(Date.UTC(yyyy,0,1)).getUTCDay() + 1) / 7));
  switch((cadenza||'').toLowerCase()) {
    case 'hourly':  return `${yyyy}-${mm}-${dd}T${hh}`;
    case 'daily':   return `${yyyy}-${mm}-${dd}`;
    case 'weekly':  return `${yyyy}-W${week}`;
    case 'monthly': return `${yyyy}-${mm}`;
    default:        return `${yyyy}-${mm}-${dd}`;
  }
}
