const now = new Date().toISOString();
const meta = $('FAOSTAT Parse Signals').item.json;

return [{
  json: {
    source: 'FAOSTAT_QCL',
    country: 'BR',
    macroarea: 'colture',
    cadenza: 'monthly',
    run_date: now,
    status: 'done',
    completed_at: now,
    latest_year: meta.latest_year || null,
  },
