const raw = ($json.text || '').trim();
const cleaned = raw.replace(/^```json\s*/i,'').replace(/^```\s*/i,'').replace(/```$/i,'').trim();
const parsed = JSON.parse(cleaned);
const base = $('FAOSTAT Parse QCL').item.json;

let pp = null;
try {
  pp = $('FAOSTAT Parse PP').item.json;
} catch (e) {
  pp = null;
}

const vars = (typeof $vars === 'object' && $vars) ? $vars : {};
const lookbackYearsRaw = Number(vars.FAOSTAT_LOOKBACK_YEARS || vars.faostat_lookback_years || $env.FAOSTAT_LOOKBACK_YEARS || 2);
let lookbackYears = Number.isFinite(lookbackYearsRaw) ? Math.trunc(lookbackYearsRaw) : 2;
if (lookbackYears < 1) lookbackYears = 1;
if (lookbackYears > 2) lookbackYears = 2;

function yearFromRow(row) {
  if (!row || typeof row !== 'object') return null;
  const y = Number((row.year ?? row.Year));
  return Number.isFinite(y) ? y : null;
}

const latestYearCandidate = Number(base.latest_year ?? (base.latest && base.latest.year));
const latestYear = Number.isFinite(latestYearCandidate) ? latestYearCandidate : new Date().getFullYear();
const minYear = latestYear - lookbackYears + 1;

function filterRecent(arr) {
  if (!Array.isArray(arr)) return [];
  return arr.filter((row) => {
    const y = yearFromRow(row);
    return y === null || y >= minYear;
  });
}

function keepIfRecent(row) {
  if (!row || typeof row !== 'object') return null;
  const y = yearFromRow(row);
  return y === null || y >= minYear ? row : null;
}

const yearlySeries = filterRecent(base.yearly_series);
const ppMonthlySeries = pp ? filterRecent(pp.pp_recent_monthly_series) : [];
const ppAnnualSeries = pp ? filterRecent(pp.pp_recent_annual_series) : [];

const chartFields = Array.isArray(base._chart_fields) ? base._chart_fields.slice() : [];
if (ppMonthlySeries.length) {
  chartFields.push('pp_recent_monthly_series');
}

